/**
 * app/api/insights/generate/weekly/route.ts
 * POST /api/insights/generate/weekly
 * Generates this week's forecast for the authenticated user.
 * Idempotent — returns cached forecast if already generated this week.
 */

import { NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { db } from "@/lib/db";
import { getOrCreateHDChart } from "@/lib/astro/chartService";
import { generateWeeklyForecast, getThisWeeksForecast } from "@/lib/ai/forecastService";

export async function POST() {
  const session = await auth();
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const userId = session.user.id;

  const profile = await db.birthProfile.findUnique({ where: { userId } });
  if (!profile) return NextResponse.json({ error: "No birth profile found." }, { status: 404 });

  try {
    const existing = await getThisWeeksForecast(userId);
    if (existing) return NextResponse.json({ forecast: existing, cached: true });

    const chart = await getOrCreateHDChart(userId, profile);
    const forecast = await generateWeeklyForecast(userId, chart, profile.birthName);
    return NextResponse.json({ forecast, cached: false });
  } catch (err) {
    console.error("[insights/generate/weekly] failed:", err);
    return NextResponse.json({ error: "Forecast generation failed. Please try again." }, { status: 500 });
  }
}
